function safeJson(value) {
    return JSON.stringify(value).replace(/</g, "\\u003c").replace(/>/g, "\\u003e").replace(/&/g, "\\u0026");
}
/** Self-contained graph viewer so the CLI never depends on a running web app. */
export function renderOrganizationMap(organization) {
    const graph = safeJson(organization);
    const title = organization.name.replace(/[<&>]/g, "");
    const launchStatus = organization.launch?.status?.replace(/-/g, " ") ?? "map ready";
    return `<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>${title} · DeltaDotta map</title><style>
:root{--ink:#161a16;--paper:#f4f5ed;--line:#d3d7ca;--muted:#737a6e;--lime:#c8ff3c}*{box-sizing:border-box}body{margin:0;background:var(--paper);color:var(--ink);font:14px ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.top{height:64px;display:flex;align-items:center;padding:0 24px;border-bottom:1px solid var(--line);background:#fbfcf6}.brand{font-weight:750;letter-spacing:-.04em}.mark{color:var(--lime);background:var(--ink);display:inline-grid;place-items:center;width:25px;height:25px;border-radius:50%;margin-right:8px;font:22px Georgia}.status{margin-left:auto;color:#6a8129;font-size:12px}.layout{display:grid;grid-template-columns:minmax(0,1fr) 310px;min-height:calc(100vh - 64px)}main{padding:clamp(28px,5vw,70px)}.eyebrow{margin:0 0 8px;color:#747a70;font:10px ui-monospace,monospace;letter-spacing:.1em}.intro{max-width:700px}.intro h1{font:600 clamp(34px,5vw,61px)/.96 Georgia,serif;letter-spacing:-.055em;margin:0}.intro p:last-child{color:var(--muted);line-height:1.5;margin:14px 0 30px}.tree{border-top:1px solid var(--line);padding-top:45px}.levels{display:grid;gap:28px}.level{display:flex;justify-content:center;gap:14px;flex-wrap:wrap;position:relative}.level:not(:first-child):before{content:"";position:absolute;top:-28px;height:28px;border-left:1px solid #b7bcad}.node{width:190px;min-height:112px;border:1px solid var(--line);background:#fcfcf8;text-align:left;padding:13px;cursor:pointer;transition:.16s;box-shadow:0 4px 12px rgba(0,0,0,.04)}.node:hover,.node.selected{border-color:#88a84a;transform:translateY(-3px);box-shadow:0 11px 23px rgba(0,0,0,.1)}.node small,.node b,.node em{display:block}.node small{font:9px ui-monospace,monospace;color:#77952c;text-transform:uppercase}.node b{font-size:13px;margin:8px 0 4px}.node em{font-style:normal;color:var(--muted);font-size:10px;line-height:1.35}.inspector{border-left:1px solid var(--line);background:#fbfcf6;padding:26px 20px}.inspector h2{font:600 28px/1 Georgia,serif;letter-spacing:-.04em;margin:5px 0 19px}.section{border-top:1px solid var(--line);padding:14px 0}.section strong{display:block;font:10px ui-monospace,monospace;text-transform:uppercase;letter-spacing:.06em;color:#747a70;margin-bottom:7px}.section p,.section li{color:#555d53;font-size:12px;line-height:1.45}.section p{margin:0}.section ul{margin:0;padding-left:17px}.footer{position:fixed;bottom:0;left:0;right:310px;padding:10px 24px;background:#e9ecde;border-top:1px solid var(--line);font-size:10px;color:#687062}@media(max-width:760px){.layout{grid-template-columns:1fr}.inspector{border-left:0;border-top:1px solid var(--line)}.footer{position:static}.node{width:min(100%,220px)}main{padding:32px 20px}.top{padding:0 18px}}
</style></head><body><header class="top"><div class="brand"><span class="mark">Δ</span>DeltaDotta</div><span class="status">Launch: ${launchStatus}</span></header><div class="layout"><main><section class="intro"><p class="eyebrow">ORGANIZATION MAP</p><h1 id="name"></h1><p id="mission"></p></section><section class="tree"><div class="levels" id="levels"></div></section></main><aside class="inspector" id="inspector"></aside></div><footer class="footer">This local map is generated from graph.json. Preflight checks package integrity; provider permissions must enforce real access.</footer>
<script>const org=${graph};const byId=Object.fromEntries(org.roles.map(r=>[r.id,r]));const esc=s=>String(s||'').replace(/[&<>]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;'}[c]));const roots=org.roles.filter(r=>!r.reportsTo||!byId[r.reportsTo]);const depth=r=>{let d=0,p=r;while(p.reportsTo&&byId[p.reportsTo]&&d<10){d++;p=byId[p.reportsTo]}return d};function launch(role){return String(role.launchStatus||role.status||'mapped').replace(/-/g,' ')}function show(role){document.querySelectorAll('.node').forEach(n=>n.classList.toggle('selected',n.dataset.id===role.id));document.querySelector('#inspector').innerHTML='<p class="eyebrow">ROLE SKILL</p><h2>'+esc(role.title)+'</h2>'+block('Launch status',launch(role))+block('Mission',role.purpose)+list('Owns',role.owns)+list('Decision authority',role.permissions)+list('Collaborates with',role.collaborators)+block('Escalation',role.escalatesTo?(byId[role.escalatesTo]?.title||role.escalatesTo):'No escalation target declared')+block('Evidence',role.evidenceIds.length?role.evidenceIds.length+' linked source(s)':'Template role — no source link yet')}function block(label,text){return '<section class="section"><strong>'+label+'</strong><p>'+esc(text)+'</p></section>'}function list(label,items){return '<section class="section"><strong>'+label+'</strong>'+(items.length?'<ul>'+items.map(x=>'<li>'+esc(x)+'</li>').join('')+'</ul>':'<p>Not yet defined</p>')+'</section>'}document.querySelector('#name').textContent=org.name;document.querySelector('#mission').textContent=org.mission;const levels=document.querySelector('#levels');const max=Math.max(...org.roles.map(depth),0);for(let d=0;d<=max;d++){const level=document.createElement('div');level.className='level';org.roles.filter(r=>depth(r)===d).forEach(role=>{const node=document.createElement('button');node.className='node';node.dataset.id=role.id;node.innerHTML='<small>'+launch(role)+' · '+(role.evidenceIds.length?'source linked':'template')+'</small><b>'+esc(role.title)+'</b><em>'+esc(role.owns[0]||role.purpose)+'</em>';node.onclick=()=>show(role);level.appendChild(node)});if(level.children.length)levels.appendChild(level)}show(roots[0]||org.roles[0]);</script></body></html>`;
}
